Below is a Python function to check if a given set of seminorms satisfies the submultiplicative property for an m-convex Fréchet algebra. The function assumes the seminorms are stored in a list and tests the condition {\displaystyle \|ab\|_{n} \leq \|a\|_{n} \|b\|_{n}} for all pairs of elements and seminorms:

python
def is_submultiplicative(seminorms, elements):
    """
    Check if the seminorms are submultiplicative for the given elements.

    Args:
        seminorms: List of seminorm functions, where seminorms[i](x) computes the i-th seminorm of x.
        elements: List of tuples (a, b) of elements in the algebra to test.

    Returns:
        bool: True if the submultiplicative property holds for all tested pairs, False otherwise.
    """
    for n, seminorm in enumerate(seminorms):
        for a, b in elements:
            ab = a * b  # Assume * is the multiplication in the algebra
            left = seminorm(ab)
            right = seminorm(a) * seminorm(b)
            if left > right:
                return False
    return True

# Example usage:
# Define seminorms for a simple algebra (e.g., polynomial algebra with coefficient-wise seminorms)
def seminorm_0(p):
    return abs(p.coefficient(0))

seminorms = [seminorm_0]  # Extend with more seminorms as needed
# Define some elements (e.g., polynomials)
class Polynomial:
    def __init__(self, coeffs):
        self.coeffs = coeffs
    def coefficient(self, i):
        return self.coeffs[i] if i < len(self.coeffs) else 0
    def __mul__(self, other):
        # Polynomial multiplication
        result = [0] * (len(self.coeffs) + len(other.coeffs) - 1)
        for i, a in enumerate(self.coeffs):
            for j, b in enumerate(other.coeffs):
                result[i + j] += a * b
        return Polynomial(result)

a = Polynomial([1, 2])
b = Polynomial([3, 4])
elements = [(a, b)]
print(is_submultiplicative(seminorms, elements))  # Should return True for m-convex case
